1	package config
2	
3	import (
4		"encoding/json"
5		"fmt"
6		"io"
7		"os"
8		"path/filepath"
9		"regexp"
10	)
11	
12	var validUsernamePattern = regexp.MustCompile(`^[a-z][a-z0-9_-]*$`)
13	var validGitHubUsernamePattern = regexp.MustCompile(`^[a-zA-Z0-9][a-zA-Z0-9-]*$`)
14	
15	func ResolveFolder(folder string, name string) string {
16		return filepath.Join(folder, name)
17	}
18	
19	func ConfigPath(folder string, name string) string {
20		return filepath.Join(ResolveFolder(folder, name), "config.json")
21	}
22	
23	func CloudInitPath(folder string, name string) string {
24		return filepath.Join(ResolveFolder(folder, name), "cloud-init.yaml")
25	}
26	
27	func Load(folder string, name string) (*Config, string, error) {
28		return LoadFromPath(ConfigPath(folder, name))
29	}
30	
31	func LoadFromPath(path string) (*Config, string, error) {
32		data, err := os.ReadFile(path)
33		if err != nil {
34			return nil, "", fmt.Errorf("config file not found: create %s", path)
35		}
36	
37		var configuration Config
38		if err := json.Unmarshal(data, &configuration); err != nil {
39			return nil, "", fmt.Errorf("invalid JSON in %s: %w", path, err)
40		}
41	
42		ApplyDefaults(&configuration)
43	
44		if err := Validate(&configuration); err != nil {
45			return nil, "", err
46		}
47	
48		return &configuration, path, nil
49	}
50	
51	func Save(path string, configuration *Config) error {
52		data, err := json.MarshalIndent(configuration, "", "  ")
53		if err != nil {
54			return fmt.Errorf("failed to marshal config: %w", err)
55		}
56		data = append(data, '\n')
57		return os.WriteFile(path, data, 0600)
58	}
59	
60	func ApplyDefaults(configuration *Config) {
61		if configuration.VM == nil {
62			return
63		}
64		if configuration.VM.CPUs == 0 {
65			configuration.VM.CPUs = 2
66		}
67		if configuration.VM.Memory == "" {
68			configuration.VM.Memory = "2G"
69		}
70		if configuration.VM.Disk == "" {
71			configuration.VM.Disk = "20G"
72		}
73		if configuration.VM.Image == "" {
74			configuration.VM.Image = "24.04"
75		}
76		if configuration.VM.Region == "" {
77			configuration.VM.Region = "us-east-1"
78		}
79		if configuration.VM.InstanceType == "" {
80			configuration.VM.InstanceType = "t3.micro"
81		}
82		if configuration.DNS != nil && configuration.DNS.TTL == 0 {
83			configuration.DNS.TTL = 300
84		}
85		if configuration.CloudInit == nil {
86			configuration.CloudInit = &CloudInitConfig{}
87		}
88		if configuration.CloudInit.WorkingDir == "" {
89			configuration.CloudInit.WorkingDir = "/var/www/html"
90		}
91	}
92	
93	func StatePath(folder, name, providerName string) string {
94		return filepath.Join(ResolveFolder(folder, name), providerName, "config.json")
95	}
96	
97	func StateCloudInitPath(folder, name, providerName string) string {
98		return filepath.Join(ResolveFolder(folder, name), providerName, "cloud-init.yaml")
99	}
100	
101	func SaveState(folder, name, providerName string, cfg *Config) error {
102		stateDir := filepath.Join(ResolveFolder(folder, name), providerName)
103		if err := os.MkdirAll(stateDir, 0755); err != nil {
104			return fmt.Errorf("failed to create state directory %s: %w", stateDir, err)
105		}
106		return Save(filepath.Join(stateDir, "config.json"), cfg)
107	}
