1	package main
2	
3	import (
4		"context"
5		"fmt"
6		"os"
7		"path/filepath"
8		"strings"
9	
10		"github.com/emergingrobotics/goloo/internal/cloudinit"
11		"github.com/emergingrobotics/goloo/internal/config"
12		"github.com/emergingrobotics/goloo/internal/hosts"
13		"github.com/emergingrobotics/goloo/internal/provider"
14		awsprovider "github.com/emergingrobotics/goloo/internal/provider/aws"
15		doprovider "github.com/emergingrobotics/goloo/internal/provider/digitalocean"
16		"github.com/emergingrobotics/goloo/internal/provider/multipass"
17	)
18	
19	var version = "dev"
20	
21	func main() {
22		if err := run(os.Args[1:]); err != nil {
23			fmt.Fprintf(os.Stderr, "Error: %v\n", err)
24			os.Exit(1)
25		}
26	}
27	
28	type Command struct {
29		Action       string
30		VMName       string
31		ProviderFlag string
32		ConfigDir    string
33		FolderPath   string
34		Users        []string
35		Verbose      bool
36		NoHosts      bool
37	}
38	
39	var verboseEnabled bool
40	
41	func verboseLog(format string, arguments ...interface{}) {
42		if verboseEnabled {
43			fmt.Fprintf(os.Stderr, "[verbose] "+format+"\n", arguments...)
44		}
45	}
46	
47	func run(args []string) error {
48		command, err := ParseArgs(args)
49		if err != nil {
50			return err
51		}
52	
53		verboseEnabled = command.Verbose
54		ctx := context.Background()
55	
56		switch command.Action {
57		case "version":
58			fmt.Println(version)
59			return nil
60		case "help":
61			printUsage()
62			return nil
63		case "create":
64			return cmdCreate(ctx, command)
65		case "destroy":
66			return cmdDestroy(ctx, command)
67		case "list":
68			return cmdList(ctx, command)
69		case "ssh":
70			return cmdSSH(ctx, command)
71		case "status":
72			return cmdStatus(ctx, command)
73		case "stop":
74			return cmdStop(ctx, command)
75		case "start":
76			return cmdStart(ctx, command)
77		case "dns-swap":
78			return cmdDNSSwap(ctx, command)
79		default:
80			return fmt.Errorf("unknown command %q\nRun 'goloo help' for usage", command.Action)
81		}
82	}
83	
84	func ParseArgs(args []string) (*Command, error) {
85		verbose := false
86		filtered := make([]string, 0, len(args))
87		for _, arg := range args {
88			if arg == "--verbose" || arg == "-v" {
89				verbose = true
90			} else {
91				filtered = append(filtered, arg)
92			}
93		}
94		args = filtered
95	
96		if len(args) == 0 {
97			return nil, fmt.Errorf("no command provided\n\nUsage: goloo <command> <name> [flags]\nCommands: create, destroy, list, ssh, status, stop, start, dns swap\n\nRun 'goloo help' for details")
98		}
99	
100		first := args[0]
101		if first == "--version" {
102			return &Command{Action: "version"}, nil
103		}
104		if first == "--help" || first == "-h" || first == "help" {
105			return &Command{Action: "help"}, nil
106		}
107	
108		if isLegacyInvocation(args) {
109			command, err := parseLegacyArgs(args)
110			if err != nil {
111				return nil, err
112			}
113			command.Verbose = verbose
114			return command, nil
115		}
116	
117		if strings.HasPrefix(first, "-") {
118			return nil, fmt.Errorf("unknown flag %q\nRun 'goloo help' for usage", first)
119		}
120	
121		command := &Command{Action: first, Verbose: verbose}
122		remaining := args[1:]
123	
124		if command.Action == "dns" {
125			if len(remaining) == 0 {
126				return nil, fmt.Errorf("usage: goloo dns swap <name>")
127			}
128			if remaining[0] != "swap" {
129				return nil, fmt.Errorf("unknown dns subcommand %q: use 'goloo dns swap <name>'", remaining[0])
130			}
131			command.Action = "dns-swap"
132			remaining = remaining[1:]
133		}
134	
135		if command.Action == "list" {
136			for _, arg := range remaining {
137				switch arg {
138				case "--aws":
139					command.ProviderFlag = "aws"
140				case "--local":
141					command.ProviderFlag = "local"
142				case "--do", "--digitalocean":
143					command.ProviderFlag = "do"
144				default:
145					return nil, fmt.Errorf("unknown flag %q for list command", arg)
146				}
147			}
148			return command, nil
149		}
150	
151		return parseNameAndFlags(command, remaining)
152	}
153	
154	func isLegacyInvocation(args []string) bool {
155		for _, arg := range args {
156			if arg == "-c" || arg == "-d" {
157				return true
158			}
159		}
160		return false
161	}
162	
163	func parseLegacyArgs(args []string) (*Command, error) {
164		command := &Command{ProviderFlag: "aws"}
165	
166		for i := 0; i < len(args); i++ {
167			switch args[i] {
168			case "-c":
169				if command.Action == "destroy" {
170					return nil, fmt.Errorf("cannot use -c and -d together")
171				}
172				command.Action = "create"
173			case "-d":
174				if command.Action == "create" {
175					return nil, fmt.Errorf("cannot use -c and -d together")
176				}
177				command.Action = "destroy"
178			case "-n":
179				if i+1 >= len(args) {
180					return nil, fmt.Errorf("-n requires a VM name")
181				}
182				i++
183				command.VMName = args[i]
184			default:
185				return nil, fmt.Errorf("unknown flag %q: legacy syntax is 'goloo -c -n <name>' or 'goloo -d -n <name>'", args[i])
186			}
187		}
188	
189		if command.Action == "" {
190			return nil, fmt.Errorf("missing action flag: use -c (create) or -d (destroy)")
191		}
192		if command.VMName == "" {
193			return nil, fmt.Errorf("-n <name> required")
194		}
195	
196		return command, nil
197	}
198	
199	func parseNameAndFlags(command *Command, remaining []string) (*Command, error) {
200		for i := 0; i < len(remaining); i++ {
201			arg := remaining[i]
202			switch {
203			case arg == "--aws":
204				command.ProviderFlag = "aws"
205			case arg == "--local":
206				command.ProviderFlag = "local"
207			case arg == "--do" || arg == "--digitalocean":
208				command.ProviderFlag = "do"
209			case arg == "--dir":
210				if i+1 >= len(remaining) {
211					return nil, fmt.Errorf("%s requires a path argument", arg)
212				}
213				i++
214				command.ConfigDir = remaining[i]
215			case arg == "--folder" || arg == "-f":
216				if i+1 >= len(remaining) {
217					return nil, fmt.Errorf("%s requires a path argument", arg)
218				}
219				i++
220				command.FolderPath = remaining[i]
221			case arg == "--users" || arg == "-u":
222				if i+1 >= len(remaining) {
223					return nil, fmt.Errorf("%s requires a username argument", arg)
224				}
225				i++
226				for _, name := range strings.Split(remaining[i], ",") {
227					trimmed := strings.TrimSpace(name)
228					if trimmed != "" {
229						command.Users = append(command.Users, trimmed)
230					}
231				}
232			case arg == "--no-hosts":
233				command.NoHosts = true
234			case strings.HasPrefix(arg, "-"):
235				return nil, fmt.Errorf("unknown flag %q\nRun 'goloo help' for usage", arg)
236			default:
237				if command.VMName != "" {
238					return nil, fmt.Errorf("unexpected argument %q after VM name %q", arg, command.VMName)
239				}
240				command.VMName = arg
241			}
242		}
243	
244		if command.VMName == "" {
245			return nil, fmt.Errorf("VM name required: goloo %s <name>", command.Action)
246		}
247	
248		return command, nil
249	}
250	
251	func DetectProvider(providerFlag string) string {
252		if providerFlag == "aws" {
253			return "aws"
254		}
255		if providerFlag == "local" {
256			return "multipass"
257		}
258		if providerFlag == "do" || providerFlag == "digitalocean" {
259			return "digitalocean"
260		}
261		return "multipass"
262	}
263	
264	func DetectProviderForState(providerFlag, stackFolder, vmName string) string {
265		if providerFlag == "aws" {
266			return "aws"
267		}
268		if providerFlag == "local" {
269			return "multipass"
270		}
271		if providerFlag == "do" || providerFlag == "digitalocean" {
272			return "digitalocean"
273		}
274		hasLocal := config.HasState(stackFolder, vmName, "local")
275		hasAWS := config.HasState(stackFolder, vmName, "aws")
276		hasDO := config.HasState(stackFolder, vmName, "do")
277		if hasDO && !hasLocal {
278			return "digitalocean"
279		}
280		if hasAWS && !hasLocal {
281			return "aws"
282		}
283		return "multipass"
284	}
285	
286	func providerDirName(providerName string) string {
287		if providerName == "multipass" {
288			return "local"
289		}
290		if providerName == "digitalocean" {
291			return "do"
292		}
293		return providerName
294	}
295	
296	func getProvider(providerName string, region string, verbose bool) (provider.VMProvider, error) {
297		switch providerName {
298		case "aws":
299			return awsprovider.NewWithSDK(region)
300		case "multipass":
301			return multipass.New(verbose), nil
302		case "digitalocean":
303			return doprovider.New(), nil
304		default:
305			return nil, fmt.Errorf("unknown provider %q: use 'aws', 'digitalocean', or 'multipass'", providerName)
306		}
307	}
308	
309	func defaultStackFolder() string {
310		home, err := os.UserHomeDir()
311		if err != nil {
312			return "stacks"
313		}
314		return filepath.Join(home, ".config", "goloo", "stacks")
315	}
316	
317	func resolveStackFolder(command *Command) string {
318		if command.FolderPath != "" {
319			return command.FolderPath
320		}
321		if command.ConfigDir != "" {
322			return filepath.Join(command.ConfigDir, "stacks")
323		}
324		if envFolder := os.Getenv("GOLOO_STACK_FOLDER"); envFolder != "" {
325			return envFolder
326		}
327		dir := defaultStackFolder()
328		_ = os.MkdirAll(dir, 0755)
329		return dir
330	}
331	
332	func resolveStackDir(command *Command) string {
333		folder := resolveStackFolder(command)
334	
335		if command.FolderPath != "" {
336			directConfig := filepath.Join(folder, "config.json")
337			if _, err := os.Stat(directConfig); err == nil {
338				return folder
339			}
340		}
341	
342		return filepath.Join(folder, command.VMName)
343	}
344	
345	func loadConfig(command *Command) (*config.Config, string, error) {
346		stackDir := resolveStackDir(command)
347		return config.LoadFromPath(filepath.Join(stackDir, "config.json"))
348	}
349	
350	func resolveCloudInitPath(command *Command) string {
351		stackDir := resolveStackDir(command)
352		path := filepath.Join(stackDir, "cloud-init.yaml")
353		if _, err := os.Stat(path); err != nil {
354			return ""
355		}
356		return path
357	}
358	
359	func cmdCreate(ctx context.Context, command *Command) error {
360		verboseLog("loading config for %q", command.VMName)
361		configuration, configPath, err := loadConfig(command)
362		if err != nil {
363			return err
364		}
365		verboseLog("config loaded from %s (VM: %s, image: %s, cpus: %d, memory: %s, disk: %s)",
366			configPath, configuration.VM.Name, configuration.VM.Image,
367			configuration.VM.CPUs, configuration.VM.Memory, configuration.VM.Disk)
368	
369		if len(command.Users) > 0 {
370			users := make([]config.User, len(command.Users))
371			for i, githubUsername := range command.Users {
372				username := githubUsername
373				if i == 0 {
374					username = "ubuntu"
375				}
376				users[i] = config.User{
377					Username:       username,
378					GitHubUsername: githubUsername,
379				}
380			}
381			configuration.VM.Users = users
382			verboseLog("users overridden from CLI: %v", command.Users)
383		}
384	
385		providerName := DetectProvider(command.ProviderFlag)
386		verboseLog("provider: %s", providerName)
387		vmProvider, err := getProvider(providerName, configuration.VM.Region, command.Verbose)
388		if err != nil {
389			return err
390		}
391	
392		stackFolder := resolveStackFolder(command)
393		dirName := providerDirName(providerName)
394	
395		cloudInitSource := resolveCloudInitPath(command)
396		cloudInitPath := ""
397		if cloudInitSource != "" {
398			verboseLog("processing cloud-init template: %s", cloudInitSource)
399			for _, user := range configuration.VM.Users {
400				if user.GitHubUsername != "" {
401					verboseLog("fetching SSH keys from github.com/%s.keys", user.GitHubUsername)
402				}
403			}
404			processedPath, err := cloudinit.Process(cloudInitSource, configuration, cloudinit.FetchGitHubKeys)
405			if err != nil {
406				return fmt.Errorf("cloud-init processing failed: %w", err)
407			}
408			defer os.Remove(processedPath)
409			cloudInitPath = processedPath
410			verboseLog("cloud-init processed: %s", processedPath)
411		}
412	
413		verboseLog("creating VM %q via %s", configuration.VM.Name, vmProvider.Name())
414		if err := vmProvider.Create(ctx, configuration, cloudInitPath); err != nil {
415			return err
416		}
417	
418		verboseLog("saving state to %s/%s/%s/config.json", stackFolder, command.VMName, dirName)
419		if err := config.SaveState(stackFolder, command.VMName, dirName, configuration); err != nil {
420			return fmt.Errorf("VM created but failed to save state: %w", err)
421		}
422	
423		if cloudInitPath != "" {
424			if err := config.CopyCloudInitToState(stackFolder, command.VMName, dirName, cloudInitPath); err != nil {
425				verboseLog("warning: failed to copy cloud-init to state: %v", err)
426			}
427		}
428	
429		hostsAdded := false
430		if providerName == "multipass" && !command.NoHosts && configuration.Local != nil && configuration.Local.IP != "" {
431			hostnames := hosts.BuildHostnames(configuration.VM.Name, dnsHostname(configuration), dnsDomain(configuration))
432			fmt.Println("Adding hostname to /etc/hosts (requires sudo)")
433			if err := hosts.Add(configuration.VM.Name, configuration.Local.IP, hostnames, command.Verbose); err != nil {
434				fmt.Fprintf(os.Stderr, "Warning: failed to update /etc/hosts: %v\n", err)
435				fmt.Fprintln(os.Stderr, hosts.ManualInstructions(configuration.Local.IP, hostnames, configuration.VM.Name))
436			} else {
437				hostsAdded = true
438				configuration.Local.HostsEntry = true
439				if saveErr := config.SaveState(stackFolder, command.VMName, dirName, configuration); saveErr != nil {
440					fmt.Fprintf(os.Stderr, "Warning: hosts entry added but failed to save state: %v\n", saveErr)
441				}
442			}
443		}
444	
445		fmt.Printf("Created %s via %s\n", configuration.VM.Name, vmProvider.Name())
446		if configuration.AWS != nil && configuration.AWS.PublicIP != "" {
447			fmt.Printf("IP: %s\n", configuration.AWS.PublicIP)
448		} else if configuration.DO != nil && configuration.DO.PublicIP != "" {
449			fmt.Printf("IP: %s\n", configuration.DO.PublicIP)
450		} else if configuration.Local != nil && configuration.Local.IP != "" {
451			fmt.Printf("IP: %s\n", configuration.Local.IP)
452		}
453		if configuration.AWS != nil && configuration.AWS.FQDN != "" {
454			fmt.Printf("DNS: %s\n", configuration.AWS.FQDN)
455		}
456		if configuration.DO != nil && configuration.DO.FQDN != "" {
457			fmt.Printf("DNS: %s\n", configuration.DO.FQDN)
458		}
459		if hostsAdded {
460			hostnames := hosts.BuildHostnames(configuration.VM.Name, dnsHostname(configuration), dnsDomain(configuration))
461			fmt.Printf("Hosts: %s\n", strings.Join(hostnames, ", "))
462		}
463		fmt.Printf("SSH: goloo ssh %s\n", configuration.VM.Name)
464	
465		return nil
466	}
