1	package cloudinit
2	
3	import (
4		"fmt"
5		"os"
6		"strings"
7	
8		"github.com/emergingrobotics/goloo/internal/config"
9	)
10	
11	type KeyFetchFunc func(username string) (string, error)
12	
13	func Process(templatePath string, configuration *config.Config, fetchKeys KeyFetchFunc) (string, error) {
14		content, err := os.ReadFile(templatePath)
15		if err != nil {
16			return "", fmt.Errorf("cloud-init template not found: %s", templatePath)
17		}
18	
19		users := getUsers(configuration)
20	
21		keysPerUser := make(map[string]string)
22		for _, user := range users {
23			if user.GitHubUsername == "" {
24				continue
25			}
26			keys, err := fetchKeys(user.GitHubUsername)
27			if err != nil {
28				return "", err
29			}
30			keysPerUser[user.Username] = keys
31		}
32	
33		rendered := string(content)
34	
35		if strings.Contains(rendered, "{{") {
36			templateData := buildTemplateData(configuration, keysPerUser)
37			rendered, err = renderGoTemplate(rendered, templateData)
38			if err != nil {
39				return "", err
40			}
41		}
42	
43		rendered = substituteVariables(rendered, users, keysPerUser)
44	
45		temporaryFile, err := os.CreateTemp("", "goloo-cloudinit-*.yaml")
46		if err != nil {
47			return "", fmt.Errorf("failed to create temp file: %w", err)
48		}
49		defer temporaryFile.Close()
50	
51		if _, err := temporaryFile.WriteString(rendered); err != nil {
52			os.Remove(temporaryFile.Name())
53			return "", fmt.Errorf("failed to write processed cloud-init: %w", err)
54		}
55	
56		return temporaryFile.Name(), nil
57	}
58	
59	func getUsers(configuration *config.Config) []config.User {
60		if configuration != nil && configuration.VM != nil {
61			return configuration.VM.Users
62		}
63		return nil
64	}
65	
66	func substituteVariables(content string, users []config.User, keysPerUser map[string]string) string {
67		result := content
68	
69		if len(users) > 0 {
70			firstUsername := users[0].Username
71			if keys, exists := keysPerUser[firstUsername]; exists {
72				result = substituteKey(result, "${SSH_PUBLIC_KEY}", keys)
73			}
74		}
75	
76		for username, keys := range keysPerUser {
77			placeholder := fmt.Sprintf("${SSH_PUBLIC_KEY_%s}", strings.ToUpper(username))
78			result = substituteKey(result, placeholder, keys)
79		}
80	
81		return result
82	}
83	
84	func substituteKey(content string, placeholder string, keys string) string {
85		keyLines := splitKeys(keys)
86	
87		if len(keyLines) <= 1 {
88			return strings.ReplaceAll(content, placeholder, keys)
89		}
90	
91		contentLines := strings.Split(content, "\n")
92		var result []string
93		for _, line := range contentLines {
94			if !strings.Contains(line, placeholder) {
95				result = append(result, line)
96				continue
97			}
98	
99			index := strings.Index(line, placeholder)
100			prefix := line[:index]
101	
102			for _, key := range keyLines {
103				result = append(result, prefix+key)
104			}
105		}
106		return strings.Join(result, "\n")
107	}
108	
109	func splitKeys(keys string) []string {
110		var result []string
111		for _, line := range strings.Split(keys, "\n") {
112			line = strings.TrimSpace(line)
113			if line != "" {
114				result = append(result, line)
115			}
116		}
